                                        <input id="select-all-warehouses" type="checkbox" checked={selectedWarehouses.length === allWarehouses.length && allWarehouses.length > 0} onChange={(e) => setSelectedWarehouses(e.target.checked ? allWarehouses : [])} className="h-4 w-4 rounded border-gray-300 text-indigo-600 focus:ring-indigo-500" />
                                        <label htmlFor="select-all-warehouses" className="ml-2 text-sm font-medium text-gray-900 dark:text-gray-100">Chọn tất cả</label>
                                    </div>
                                    <div className="flex-grow overflow-y-auto max-h-48">
                                        {allWarehouses.filter(opt => opt.toLowerCase().includes(warehouseSearchTerm.toLowerCase())).map(option => (
