                                                <input id={`wh-opt-${option}`} type="checkbox" checked={selectedWarehouses.includes(option)} onChange={() => {
                                                    setSelectedWarehouses(prev => prev.includes(option) ? prev.filter(item => item !== option) : [...prev, option]);
