                    <button onClick={() => setModalState({ type: null })} className="py-2 px-4 rounded-lg shadow-sm text-sm font-semibold text-slate-700 bg-white hover:bg-slate-50 border border-slate-300 transition-colors">Hủy</button>
                    <button onClick={handleDeleteTable} className="py-2 px-6 rounded-lg shadow-sm text-sm font-semibold text-white bg-red-600 hover:bg-red-700 transition-colors">Xác nhận Xóa</button>
                </div>
            </ModalWrapper>

            <ModalWrapper
                isOpen={modalState.type === 'CONFIRM_DELETE_COLUMN'}
                onClose={() => setModalState({ type: null })}
                title="Xác nhận Xóa Cột"
                subTitle={`Bạn sắp xóa cột "${modalState.data?.columnName || ''}"`}
                titleColorClass="text-red-600 dark:text-red-400"
                maxWidthClass="max-w-md"
            >
                <div className="p-6">
                    <p>Hành động này sẽ xóa vĩnh viễn cột này khỏi bảng. Bạn có chắc chắn muốn tiếp tục?</p>
                </div>
                <div className="p-4 flex justify-end gap-3 bg-slate-100 dark:bg-slate-800 rounded-b-xl border-t border-slate-200 dark:border-slate-700">
                    <button onClick={() => setModalState({ type: null })} className="py-2 px-4 rounded-lg shadow-sm text-sm font-semibold text-slate-700 bg-white hover:bg-slate-50 border border-slate-300 transition-colors">Hủy</button>
                    <button onClick={handleConfirmDeleteColumn} className="py-2 px-6 rounded-lg shadow-sm text-sm font-semibold text-white bg-red-600 hover:bg-red-700 transition-colors">Xác nhận Xóa</button>
                </div>
            </ModalWrapper>
        </div>
    );
};

export default EmployeeAnalysis;

import React, { useMemo, useState, forwardRef, useEffect, useRef } from 'react';
import type { Employee, EmployeeData } from '../../types';
import { abbreviateName, formatCurrency, formatQuantity, formatQuantityWithFraction } from '../../utils/dataUtils';
import { Icon } from '../common/Icon';
import { getPerformanceTableAnalysis } from '../../services/aiService';
import { getThemeMap, saveThemeMap, getDailyTarget, saveDailyTarget } from '../../services/dbService';
import { useDashboardContext } from '../../contexts/DashboardContext';

declare const lucide: any;

interface PerformanceTableProps {
    employeeData: EmployeeData;
    onEmployeeClick: (employeeName: string) => void;
    onExport?: () => void;
    isExporting?: boolean;
}

type SortKey = keyof Employee | 'name' | 'percentHT' | 'dtVuot' | 'target';
type SortDirection = 'asc' | 'desc';
type GroupType = 'doanhThu' | 'khaiThac' | 'vuotTroi';

const getTraChamPercentClass = (percentage: number) => {
    if (isNaN(percentage)) return 'text-slate-400 font-medium';
    if (percentage >= 45) return 'text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-lg font-bold';
    if (percentage >= 35) return 'text-amber-600 bg-amber-50 px-2 py-0.5 rounded-lg font-bold';
    return 'text-rose-600 bg-rose-50 px-2 py-0.5 rounded-lg font-bold';
};

const getProgressBarColor = (percent: number) => {
    if (percent >= 100) return 'bg-gradient-to-r from-emerald-400 to-teal-500';
    if (percent >= 80) return 'bg-gradient-to-r from-blue-400 to-indigo-500';
    if (percent >= 50) return 'bg-gradient-to-r from-amber-400 to-orange-500';
    return 'bg-gradient-to-r from-red-400 to-rose-500';
};

const getPercentTextColor = (percent: number) => {
    if (percent >= 100) return 'text-emerald-600 dark:text-emerald-400';
    if (percent >= 80) return 'text-blue-600 dark:text-blue-400';
    if (percent >= 50) return 'text-amber-600 dark:text-amber-400';
    return 'text-rose-600 dark:text-rose-400';
};

// Apple-style subtle themes
const themes = {
    vuotTroi: { iconBg: 'bg-indigo-100 text-indigo-600', accent: 'indigo' },
    doanhThu: { iconBg: 'bg-emerald-100 text-emerald-600', accent: 'emerald' },
    khaiThac: { iconBg: 'bg-blue-100 text-blue-600', accent: 'blue' }
};

const RenderSingleTable = ({
    groupType,
    sortConfig,
    onSort,
    tableRef,
    onSingleExport,
    isExporting,
    groupedData,
    outstandingData,
    grandTotal,
    targetPerEmployee,
    fullSellerArrayLength,
    onEmployeeClick,
    isEditingTarget,
    targetInputRef,
    setTargetPerEmployee,
    handleSaveTarget,
    setIsEditingTarget,
    tempTarget,
    setTempTarget,
}: {
    groupType: GroupType;
    sortConfig: { key: SortKey; direction: SortDirection };
    onSort: (key: SortKey) => void;
    tableRef: React.RefObject<HTMLDivElement>;
    onSingleExport: () => void;
    isExporting?: boolean;
    groupedData: { [key: string]: Employee[] };
    outstandingData: { [key: string]: Employee[] };
    grandTotal: any;
    targetPerEmployee: number;
    fullSellerArrayLength: number;
    onEmployeeClick: (name: string) => void;
    isEditingTarget: boolean;
    targetInputRef: React.RefObject<HTMLInputElement>;
    setTargetPerEmployee: (val: number) => void;
    handleSaveTarget: () => void;
    setIsEditingTarget: (val: boolean) => void;
    tempTarget: string;
    setTempTarget: (val: string) => void;
}) => {
    const [copySuccess, setCopySuccess] = useState(false);
    const [columnCopySuccess, setColumnCopySuccess] = useState<string | null>(null);

    let title = "";
    let subTitle = "";
    let icon = "";
    let headers: { label: string, key: SortKey, align?: 'left'|'center'|'right', width?: string }[] = [];
    let dataToRender: any = groupedData;
    const theme = themes[groupType];

    if (groupType === 'doanhThu') {
        title = 'Hiệu Quả Doanh Thu';
        subTitle = 'Phân tích doanh thu & hiệu quả quy đổi';
        icon = 'wallet';
        headers = [
            { label: 'Thực', key: 'doanhThuThuc', align: 'center' }, 
            { label: 'DTQĐ', key: 'doanhThuQD', align: 'center' },
            { label: 'HQQĐ', key: 'hieuQuaValue', align: 'center' }, 
            { label: '%T.Chậm', key: 'dtTraChamPercent_CE_ICT' as any, align: 'center' },
            { label: 'Weak', key: 'weakPointsRevenue' as any, align: 'center', width: 'w-12' }
        ];
    } else if (groupType === 'khaiThac') {
        title = 'Hiệu Quả Khai Thác';
        subTitle = 'Tiếp cận khách hàng & Bán kèm';
        icon = 'layers';
        headers = [
            { label: 'T.Cận', key: 'slTiepCan', align: 'center' }, 
            { label: 'CE/ICT', key: 'slCE_ICT' as any, align: 'center' },
            { label: 'T.Chậm', key: 'slTraCham_CE_ICT' as any, align: 'center' }, 
            { label: '%T.Chậm', key: 'traChamPercent_CE_ICT' as any, align: 'center' },
            { label: 'Weak', key: 'weakPointsExploitation' as any, align: 'center', width: 'w-12' }
        ];
    } else { // vuotTroi
        const todayDate = new Date().toLocaleDateString('vi-VN', {day: '2-digit', month: '2-digit'});
        title = `Mục Tiêu Vượt Trội`;
        subTitle = `Cập nhật ngày ${todayDate}`;
        icon = 'trophy';
        headers = [
            { label: 'Thực', key: 'doanhThuThuc', align: 'center' },
            { label: 'DTQĐ', key: 'doanhThuQD', align: 'center' },
            { label: 'Target', key: 'target' as SortKey, align: 'center' },
            { label: '%HT', key: 'percentHT', align: 'center', width: 'w-24' },
            { label: 'HQQĐ', key: 'hieuQuaValue', align: 'center' },
            { label: 'Vượt', key: 'dtVuot', align: 'center' }
        ];
        dataToRender = outstandingData;
    }

    const handleCopyBottom40 = (e: React.MouseEvent, key: SortKey, label: string) => {
        e.stopPropagation();
        if (!dataToRender) return;
        const allEmployees = Object.values(dataToRender).flat() as any[];
        if (allEmployees.length === 0) return;

        const sorted = [...allEmployees].sort((a, b) => (a[key] ?? 0) - (b[key] ?? 0));
        const initialCutoff = Math.ceil(sorted.length * 0.4);
        const valueAtCutoff = sorted[initialCutoff - 1]?.[key] ?? 0;

        let finalSelection = valueAtCutoff <= 0 ? sorted.filter(emp => (emp[key] ?? 0) <= 0) : sorted.slice(0, initialCutoff);
        const getId = (n: string) => n.split(/[-–]/)[0].trim();

        let content = `⚠️ CẢNH BÁO: DANH SÁCH ${label.toUpperCase()} THẤP (BOTTOM 40%)\nCác bạn sau cần tập trung cải thiện chỉ số này ngay:\n`;
        finalSelection.forEach(e => content += `@${getId(e.name)}\n`);

        navigator.clipboard.writeText(content).then(() => {
            setColumnCopySuccess(String(key));
            setTimeout(() => setColumnCopySuccess(null), 2000);
        });
    };

    const renderHeader = (h: { label: string, key: SortKey, align?: string, width?: string }) => {
        const isTargetHeader = h.label === 'Target' && groupType === 'vuotTroi';
        const canCopy = groupType === 'vuotTroi' && ['doanhThuThuc', 'doanhThuQD', 'percentHT', 'dtVuot', 'hieuQuaValue', 'dtTraChamPercent_CE_ICT'].includes(String(h.key));
        const alignClass = h.align === 'right' ? 'text-right' : h.align === 'center' ? 'text-center' : 'text-left';

        if (isTargetHeader && isEditingTarget) {
            return (
                <th key={String(h.key)} className="px-2 py-3 align-middle">
                    <input 
                        ref={targetInputRef}
                        type="number" 
                        value={tempTarget} 
                        onChange={(e) => setTempTarget(e.target.value)}
                        onBlur={handleSaveTarget}
                        className="w-full px-2 py-1 text-xs text-center border-2 border-indigo-500 rounded-lg bg-white shadow-sm focus:outline-none focus:ring-2 focus:ring-indigo-200"
                        autoFocus
                        onKeyDown={(e) => {
                            if (e.key === 'Enter') handleSaveTarget();
                            if (e.key === 'Escape') setIsEditingTarget(false);
                        }}
                    />
                </th>
            );
        }

        return (
            <th 
                key={String(h.key)}
                onClick={() => isTargetHeader ? (setTempTarget(String(targetPerEmployee)), setIsEditingTarget(true)) : onSort(h.key)}
                className={`px-3 py-3 text-[10px] font-black uppercase tracking-wider text-slate-400 cursor-pointer group/header select-none ${alignClass} ${h.width || ''}`}
            >
                <div className={`flex items-center gap-1 ${h.align === 'right' ? 'justify-end' : h.align === 'center' ? 'justify-center' : 'justify-start'}`}>
                    {h.label}
                    {isTargetHeader && <Icon name="edit-3" size={3} className="opacity-50 group-hover/header:opacity-100" />}
                    {canCopy && (
                        <button onClick={(e) => handleCopyBottom40(e, h.key, h.label)} className="opacity-0 group-hover/header:opacity-100 p-1 hover:text-red-500 transition-opacity">
                            <Icon name="copy" size={3} />
                        </button>
                    )}
                    {sortConfig.key === h.key && (
                        <Icon name={sortConfig.direction === 'asc' ? 'arrow-up' : 'arrow-down'} size={3} className="text-indigo-500" />
                    )}
                </div>
                {columnCopySuccess === String(h.key) && (
                    <div className="absolute inset-0 bg-emerald-500 text-white text-[9px] flex items-center justify-center rounded-lg animate-fade-in">Copied!</div>
                )}
            </th>
        );
    };

    const handleCopyRanking = () => {
        if (groupType !== 'vuotTroi' || !dataToRender) return;
        const allEmployees = Object.values(dataToRender).flat() as any[];
        if (allEmployees.length === 0) return;

        const sorted = [...allEmployees].sort((a, b) => b.percentHT - a.percentHT);
        const top3 = sorted.slice(0, 3);
        const bottom30 = sorted.slice(-Math.ceil(sorted.length * 0.3));
        const getId = (n: string) => n.split(/[-–]/)[0].trim();

        let content = `🌟 VINH DANH TOP 3 CHIẾN BINH XUẤT SẮC 🌟\n`;
        top3.forEach(e => content += `@${getId(e.name)}\n`);
        content += `\n⚠️ CẢNH BÁO ĐỎ: NHÓM CUỐI BẢNG ⚠️\n`;
        bottom30.forEach(e => content += `@${getId(e.name)}\n`);

        navigator.clipboard.writeText(content).then(() => {
            setCopySuccess(true);
            setTimeout(() => setCopySuccess(false), 2000);
        });
    };

    const showDeptHeaders = dataToRender && (Object.keys(dataToRender).length > 1 || (Object.keys(dataToRender).length === 1 && Object.keys(dataToRender)[0] !== 'Không Phân Ca'));
    const medals = ['🥇', '🥈', '🥉'];

    if (!dataToRender || Object.keys(dataToRender).length === 0) {
        return (
            <div ref={tableRef} className="bg-white dark:bg-slate-900 rounded-[1.5rem] shadow-sm border border-slate-100 dark:border-slate-800 p-8 flex flex-col items-center justify-center h-full">
                <Icon name="inbox" size={8} className="text-slate-300 mb-2" />
                <p className="text-slate-500 dark:text-slate-400 font-medium">Không có dữ liệu hiển thị</p>
            </div>
        );
    }

    return (
        <div ref={tableRef} className="bg-white dark:bg-slate-900 rounded-[1.5rem] shadow-sm border border-slate-100 dark:border-slate-800 overflow-hidden flex flex-col h-full">
            {/* Apple-style Card Header */}
            <div 
                className="px-6 py-5 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center bg-white dark:bg-slate-900 sticky top-0 z-20 group/header"
                onClick={handleCopyRanking}
            >
                <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${theme.iconBg} shadow-sm`}>
                        <Icon name={icon} size={6} />
                    </div>
                    <div>
                        <h3 className="text-lg font-black text-slate-800 dark:text-white leading-tight">{title}</h3>
                        <p className="text-xs font-medium text-slate-400">{subTitle}</p>
                    </div>
                </div>

                <div className="flex items-center gap-2 opacity-0 group-hover:header:opacity-100 transition-opacity">
                    {groupType === 'vuotTroi' && (
                        <span className="text-xs font-bold text-slate-400 mr-2 flex items-center gap-1 cursor-pointer">
                            {copySuccess ? <span className="text-emerald-500">Đã chép!</span> : <><Icon name="copy" size={3}/> Copy Top/Bot</>}
                        </span>
                    )}
                    <button 
                        onClick={(e) => { e.stopPropagation(); onSingleExport(); }} 
                        disabled={isExporting} 
                        className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all"
                    >
                        <Icon name="camera" size={5} />
                    </button>
                </div>
            </div>

            <div className="overflow-x-auto custom-scrollbar flex-grow p-2">
                <table className="w-full text-left border-collapse">
                    <thead className="sticky top-0 z-10 bg-white/95 dark:bg-slate-900/95 backdrop-blur-sm">
                        <tr>
                            <th className="px-4 py-3 text-left text-[10px] font-black uppercase tracking-wider text-slate-400 w-12 text-center">#</th>
                            <th onClick={() => onSort('name')} className="px-3 py-3 text-left text-[10px] font-black uppercase tracking-wider text-slate-400 cursor-pointer min-w-[140px]">Nhân Viên</th>
                            {headers.map(h => renderHeader(h))}
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50 dark:divide-slate-800/50">
                        {Object.entries(dataToRender).map(([dept, employees]: [string, any[]]) => {
                            const sortedEmployees = [...employees].sort((a, b) => {
                                // Robust sort logic inside
                                const valA = (a as any)[sortConfig.key]; 
                                const valB = (b as any)[sortConfig.key];

                                if (valA === undefined || valA === null) return 1;
                                if (valB === undefined || valB === null) return -1;

                                if (typeof valA === 'number' && typeof valB === 'number') {
                                    return sortConfig.direction === 'asc' ? valA - valB : valB - valA;
                                }
                                if (typeof valA === 'string' && typeof valB === 'string') {
                                    return sortConfig.direction === 'asc' ? valA.localeCompare(valB) : valB.localeCompare(valA);
                                }
                                return (a.name || '').localeCompare(b.name || '');
                            });

                            return (
                            <React.Fragment key={dept}>
                                {showDeptHeaders && (
                                    <tr className="bg-slate-50/50 dark:bg-slate-800/20">
                                        <td colSpan={2 + headers.length} className="px-4 py-2 text-xs font-black text-slate-500 uppercase tracking-widest">
                                            <div className="flex items-center gap-2"><Icon name="users" size={3} /> {dept}</div>
                                        </td>
                                    </tr>
                                )}
                                {sortedEmployees.map((employee, index) => {
                                    const rankIndex = index;
                                    const medal = rankIndex < 3 ? medals[rankIndex] : null;
                                    const rankDisplay = medal ? <span className="text-lg">{medal}</span> : <span className="text-xs font-bold text-slate-400">#{rankIndex + 1}</span>;

                                    return (
                                    <tr key={employee.name} className="group hover:bg-slate-50 dark:hover:bg-slate-800/30 transition-colors">
                                        <td className="px-4 py-3 text-center">{rankDisplay}</td>
                                        <td className="px-3 py-3">
                                            <div onClick={() => onEmployeeClick(employee.name)} className="flex flex-col cursor-pointer">
                                                <span className="text-sm font-bold text-slate-700 dark:text-slate-200 group-hover:text-indigo-600 transition-colors truncate">
                                                    {abbreviateName(employee.name)}
                                                </span>
                                            </div>
                                        </td>
                                        {headers.map(h => (
                                            <td key={h.key} className={`px-3 py-3 text-sm ${h.align === 'right' ? 'text-right' : h.align === 'center' ? 'text-center' : 'text-left'}`}>
                                                <div className="flex flex-col justify-center h-full">
                                                    { h.key === 'doanhThuThuc' && <span className="text-slate-500 font-medium">{formatCurrency(employee.doanhThuThuc)}</span> }
                                                    { h.key === 'doanhThuQD' && <span className="font-bold text-slate-800 dark:text-white">{formatCurrency(employee.doanhThuQD)}</span> }
                                                    { h.key === 'hieuQuaValue' && <span className={`font-bold ${employee.hieuQuaValue < 35 ? 'text-rose-500' : 'text-emerald-600'}`}>{(employee.hieuQuaValue || 0).toFixed(0)}%</span> }

                                                    {/* Custom Metrics with Safe Checks */}
                                                    { h.key === 'dtTraChamPercent_CE_ICT' && <span className={getTraChamPercentClass(employee.dtTraChamPercent_CE_ICT || 0)}>{(employee.dtTraChamPercent_CE_ICT || 0).toFixed(0)}%</span> }
                                                    { h.key === 'weakPointsRevenue' && <span className={`font-black ${employee.weakPointsRevenue > 0 ? 'text-rose-500 bg-rose-50 px-2 rounded' : 'text-slate-300'}`}>{employee.weakPointsRevenue || '-'}</span> }

                                                    { h.key === 'slTiepCan' && <span className="font-bold text-slate-600">{formatQuantity(employee.slTiepCan)}</span> }
                                                    { h.key === 'slCE_ICT' && <span className="text-slate-500">{formatQuantity(employee.slCE_ICT)}</span> }
                                                    { h.key === 'slTraCham_CE_ICT' && <span className="text-slate-500">{formatQuantity(employee.slTraCham_CE_ICT)}</span> }
                                                    { h.key === 'traChamPercent_CE_ICT' && <span className={getTraChamPercentClass(employee.traChamPercent_CE_ICT || 0)}>{(employee.traChamPercent_CE_ICT || 0).toFixed(0)}%</span> }
                                                    { h.key === 'weakPointsExploitation' && <span className={`font-black ${employee.weakPointsExploitation > 0 ? 'text-rose-500 bg-rose-50 px-2 rounded' : 'text-slate-300'}`}>{employee.weakPointsExploitation || '-'}</span> }

                                                    {/* Targets */}
                                                    { h.key === 'target' && <span className="text-slate-400 text-xs">{formatCurrency(employee.target, 0).replace('Tr', '')}</span> }
                                                    { h.key === 'percentHT' && (
                                                        <div className="w-full flex flex-col gap-1">
                                                            <div className="flex justify-center">
                                                                <span className={`text-[10px] font-black ${getPercentTextColor(employee.percentHT || 0)}`}>{(employee.percentHT || 0).toFixed(0)}%</span>
                                                            </div>
                                                            <div className="h-1.5 w-full bg-slate-100 dark:bg-slate-700 rounded-full overflow-hidden">
                                                                <div className={`h-full rounded-full ${getProgressBarColor(employee.percentHT || 0)}`} style={{ width: `${Math.min(employee.percentHT || 0, 100)}%` }}></div>
                                                            </div>
                                                        </div>
                                                    )}
                                                    { h.key === 'dtVuot' && <span className={`font-bold ${(employee.dtVuot || 0) > 0 ? 'text-emerald-600' : 'text-slate-300'}`}>{(employee.dtVuot || 0) > 0 ? `+${formatCurrency(employee.dtVuot)}` : '-'}</span> }
                                                </div>
                                            </td>
                                        ))}
                                    </tr>
                                )})}
                            </React.Fragment>
                        )})}
                    </tbody>
                    <tfoot className="bg-slate-50 dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800">
                        <tr>
                            <td colSpan={2} className="px-6 py-4 text-xs font-black text-slate-500 uppercase tracking-widest">Tổng cộng</td>
                            {headers.map(h => (
                                <td key={h.key} className={`px-3 py-4 ${h.align === 'right' ? 'text-right' : h.align === 'center' ? 'text-center' : 'text-left'} font-bold text-slate-700 dark:text-slate-200 text-sm`}>
                                    { h.key === 'doanhThuThuc' && formatCurrency(grandTotal?.doanhThuThuc || 0) }
                                    { h.key === 'doanhThuQD' && <span className="text-indigo-600">{formatCurrency(grandTotal?.doanhThuQD || 0)}</span> }
                                    { h.key === 'hieuQuaValue' && <span className={(grandTotal?.hieuQuaValue || 0) < 35 ? 'text-rose-500' : 'text-emerald-600'}>{(grandTotal?.hieuQuaValue || 0).toFixed(0)}%</span> }
                                    { h.key === 'slTiepCan' && formatQuantity(grandTotal?.slTiepCan || 0) }
                                    { h.key === 'dtVuot' && <span className="text-emerald-600">{formatCurrency((grandTotal?.doanhThuQD || 0) - (targetPerEmployee * fullSellerArrayLength))}</span> }
                                    {/* Add other summary fields as needed */}
                                    { !['doanhThuThuc', 'doanhThuQD', 'hieuQuaValue', 'slTiepCan', 'dtVuot'].includes(h.key as string) && '-' }
                                </td>
                            ))}
                        </tr>
                    </tfoot>
                </table>
            </div>
        </div>
    );
};

const PerformanceTable = forwardRef<HTMLDivElement, PerformanceTableProps>(({ employeeData, onEmployeeClick, onExport, isExporting }, ref) => {
    const [activeTab, setActiveTab] = useState<GroupType>('doanhThu');
    const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: SortDirection }>({ key: 'doanhThuQD', direction: 'desc' });
    const [targetPerEmployee, setTargetPerEmployee] = useState(150000000); 
    const [isEditingTarget, setIsEditingTarget] = useState(false);
    const [tempTarget, setTempTarget] = useState(String(targetPerEmployee));
    const targetInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        getDailyTarget().then(target => {
            if (target) {
                setTargetPerEmployee(target);
                setTempTarget(String(target));
            }
        });
    }, []);

    const handleSaveTarget = () => {
        const val = parseInt(tempTarget.replace(/\D/g, ''), 10);
        if (!isNaN(val) && val > 0) {
            setTargetPerEmployee(val);
            saveDailyTarget(val);
        } else {
            setTempTarget(String(targetPerEmployee));
        }
        setIsEditingTarget(false);
    };

    const handleTabChange = (newTab: GroupType) => {
        setActiveTab(newTab);
        // Reset sort config when switching tabs to avoid sorting by non-existent keys
        if (newTab === 'doanhThu') setSortConfig({ key: 'doanhThuQD', direction: 'desc' });
        else if (newTab === 'khaiThac') setSortConfig({ key: 'slTiepCan', direction: 'desc' });
        else if (newTab === 'vuotTroi') setSortConfig({ key: 'dtVuot', direction: 'desc' });
    };

    const { groupedData, outstandingData, grandTotal } = useMemo(() => {
        const sortedArray = [...employeeData.fullSellerArray].sort((a, b) => {
            // Robust sort logic at array level
            const valA = (a as any)[sortConfig.key];
            const valB = (b as any)[sortConfig.key];

            // Safety check for keys that might not exist in base employee object (e.g., from 'vuotTroi' tab)
            // If the key doesn't exist on standard employees, skip sorting or default to 0
            if (valA === undefined && valB === undefined) return 0;
            if (valA === undefined) return 1;
            if (valB === undefined) return -1;

            if (typeof valA === 'number' && typeof valB === 'number') {
                return sortConfig.direction === 'asc' ? valA - valB : valB - valA;
            }
            if (typeof valA === 'string' && typeof valB === 'string') {
                return sortConfig.direction === 'asc' ? valA.localeCompare(valB) : valB.localeCompare(valA);
            }
            return 0;
        });

        const grouped: { [key: string]: Employee[] } = {};
        sortedArray.forEach(emp => {
            if (!grouped[emp.department]) grouped[emp.department] = [];
            grouped[emp.department].push(emp);
        });

        const outstanding: { [key: string]: Employee[] } = {};

        // Calculate outstanding metrics
        const fullOutstandingArray = sortedArray.map(emp => {
            const percentHT = targetPerEmployee > 0 ? (emp.doanhThuQD / targetPerEmployee) * 100 : 0;
            const dtVuot = Math.max(0, emp.doanhThuQD - targetPerEmployee);
            return { ...emp, target: targetPerEmployee, percentHT, dtVuot };
        });

        // If sorting by calculated fields available ONLY in 'vuotTroi' mode
        if (['target', 'percentHT', 'dtVuot'].includes(sortConfig.key as string)) {
             fullOutstandingArray.sort((a, b) => {
                const valA = a[sortConfig.key as keyof typeof a] as number || 0;
                const valB = b[sortConfig.key as keyof typeof b] as number || 0;
                return sortConfig.direction === 'asc' ? valA - valB : valB - valA;
            });
        }

        fullOutstandingArray.forEach(emp => {
            if (!outstanding[emp.department]) outstanding[emp.department] = [];
            outstanding[emp.department].push(emp);
        });

        return { groupedData: grouped, outstandingData: outstanding, grandTotal: employeeData.averages }; 

    }, [employeeData, sortConfig, targetPerEmployee]);

    // Recalculate true Grand Total for footer
    const trueGrandTotal = useMemo(() => {
        const all = employeeData?.fullSellerArray || [];
        if (all.length === 0) return { doanhThuThuc: 0, doanhThuQD: 0, slTiepCan: 0, hieuQuaValue: 0 };
        return {
            doanhThuThuc: all.reduce((sum, e) => sum + e.doanhThuThuc, 0),
            doanhThuQD: all.reduce((sum, e) => sum + e.doanhThuQD, 0),
            slTiepCan: all.reduce((sum, e) => sum + e.slTiepCan, 0),
            hieuQuaValue: all.length > 0 ? (all.reduce((sum, e) => sum + e.doanhThuQD, 0) - all.reduce((sum, e) => sum + e.doanhThuThuc, 0)) / all.reduce((sum, e) => sum + e.doanhThuThuc, 0) * 100 : 0
        };
    }, [employeeData]);

    const handleSort = (key: SortKey) => {
        setSortConfig(current => ({
            key,
            direction: current.key === key && current.direction === 'desc' ? 'asc' : 'desc'
        }));
    };

    return (
        <div className="flex flex-col h-full gap-4">
            <div className="flex gap-2 p-1 bg-slate-100 dark:bg-slate-800 rounded-lg w-fit hide-on-export">
                <button onClick={() => handleTabChange('doanhThu')} className={`px-4 py-2 text-sm font-semibold rounded-md transition-colors ${activeTab === 'doanhThu' ? 'bg-white dark:bg-slate-700 text-indigo-600 dark:text-white shadow-sm' : 'text-slate-600 dark:text-slate-400 hover:text-indigo-600'}`}>Doanh Thu</button>
                <button onClick={() => handleTabChange('khaiThac')} className={`px-4 py-2 text-sm font-semibold rounded-md transition-colors ${activeTab === 'khaiThac' ? 'bg-white dark:bg-slate-700 text-indigo-600 dark:text-white shadow-sm' : 'text-slate-600 dark:text-slate-400 hover:text-indigo-600'}`}>Khai Thác</button>
                <button onClick={() => handleTabChange('vuotTroi')} className={`px-4 py-2 text-sm font-semibold rounded-md transition-colors ${activeTab === 'vuotTroi' ? 'bg-white dark:bg-slate-700 text-indigo-600 dark:text-white shadow-sm' : 'text-slate-600 dark:text-slate-400 hover:text-indigo-600'}`}>Vượt Trội</button>
            </div>

            <RenderSingleTable 
                groupType={activeTab}
                sortConfig={sortConfig}
                onSort={handleSort}
                tableRef={ref as any}
                onSingleExport={onExport || (() => {})} 
                isExporting={isExporting}
                groupedData={groupedData}
                outstandingData={outstandingData}
                grandTotal={trueGrandTotal}
                targetPerEmployee={targetPerEmployee}
                fullSellerArrayLength={employeeData.fullSellerArray.length}
                onEmployeeClick={onEmployeeClick}
                isEditingTarget={isEditingTarget}
                targetInputRef={targetInputRef}
                setTargetPerEmployee={setTargetPerEmployee}
                handleSaveTarget={handleSaveTarget}
                setIsEditingTarget={setIsEditingTarget}
                tempTarget={tempTarget}
                setTempTarget={setTempTarget}
            />
        </div>
    );
});

export default PerformanceTable;

import React, { useMemo, useState, forwardRef, useEffect, useRef } from 'react';
import type { Employee, EmployeeData } from '../../types';
import { abbreviateName, formatCurrency, formatQuantity, formatQuantityWithFraction } from '../../utils/dataUtils';
import { Icon } from '../common/Icon';
import { getPerformanceTableAnalysis } from '../../services/aiService';
import { getThemeMap, saveThemeMap, getDailyTarget, saveDailyTarget } from '../../services/dbService';
import { useDashboardContext } from '../../contexts/DashboardContext';

declare const lucide: any;

interface PerformanceTableProps {
    employeeData: EmployeeData;
    onEmployeeClick: (employeeName: string) => void;
    onExport?: () => void;
    isExporting?: boolean;
}

type SortKey = keyof Employee | 'name' | 'percentHT' | 'dtVuot' | 'target';
type SortDirection = 'asc' | 'desc';
type GroupType = 'doanhThu' | 'khaiThac' | 'vuotTroi';

const getTraChamPercentClass = (percentage: number) => {
    if (isNaN(percentage)) return 'text-slate-400 font-medium';
    if (percentage >= 45) return 'text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-lg font-bold';
    if (percentage >= 35) return 'text-amber-600 bg-amber-50 px-2 py-0.5 rounded-lg font-bold';
    return 'text-rose-600 bg-rose-50 px-2 py-0.5 rounded-lg font-bold';
};

const getProgressBarColor = (percent: number) => {
    if (percent >= 100) return 'bg-gradient-to-r from-emerald-400 to-teal-500';
    if (percent >= 80) return 'bg-gradient-to-r from-blue-400 to-indigo-500';
    if (percent >= 50) return 'bg-gradient-to-r from-amber-400 to-orange-500';
    return 'bg-gradient-to-r from-red-400 to-rose-500';
};

const getPercentTextColor = (percent: number) => {
    if (percent >= 100) return 'text-emerald-600 dark:text-emerald-400';
    if (percent >= 80) return 'text-blue-600 dark:text-blue-400';
    if (percent >= 50) return 'text-amber-600 dark:text-amber-400';
    return 'text-rose-600 dark:text-rose-400';
};

// Apple-style subtle themes
const themes = {
    vuotTroi: { iconBg: 'bg-indigo-100 text-indigo-600', accent: 'indigo' },
    doanhThu: { iconBg: 'bg-emerald-100 text-emerald-600', accent: 'emerald' },
    khaiThac: { iconBg: 'bg-blue-100 text-blue-600', accent: 'blue' }
};

const RenderSingleTable = ({
    groupType,
    sortConfig,
    onSort,
    tableRef,
    onSingleExport,
    isExporting,
    groupedData,
    outstandingData,
    grandTotal,
    targetPerEmployee,
    fullSellerArrayLength,
    onEmployeeClick,
    isEditingTarget,
    targetInputRef,
    setTargetPerEmployee,
    handleSaveTarget,
    setIsEditingTarget,
    tempTarget,
    setTempTarget,
}: {
    groupType: GroupType;
    sortConfig: { key: SortKey; direction: SortDirection };
    onSort: (key: SortKey) => void;
    tableRef: React.RefObject<HTMLDivElement>;
    onSingleExport: () => void;
    isExporting?: boolean;
    groupedData: { [key: string]: Employee[] };
    outstandingData: { [key: string]: Employee[] };
    grandTotal: any;
    targetPerEmployee: number;
    fullSellerArrayLength: number;
    onEmployeeClick: (name: string) => void;
    isEditingTarget: boolean;
    targetInputRef: React.RefObject<HTMLInputElement>;
    setTargetPerEmployee: (val: number) => void;
    handleSaveTarget: () => void;
    setIsEditingTarget: (val: boolean) => void;
    tempTarget: string;
    setTempTarget: (val: string) => void;
}) => {
    const [copySuccess, setCopySuccess] = useState(false);
    const [columnCopySuccess, setColumnCopySuccess] = useState<string | null>(null);

    let title = "";
    let subTitle = "";
    let icon = "";
    let headers: { label: string, key: SortKey, align?: 'left'|'center'|'right', width?: string }[] = [];
    let dataToRender: any = groupedData;
    const theme = themes[groupType];

    if (groupType === 'doanhThu') {
        title = 'Hiệu Quả Doanh Thu';
        subTitle = 'Phân tích doanh thu & hiệu quả quy đổi';
        icon = 'wallet';
        headers = [
            { label: 'Thực', key: 'doanhThuThuc', align: 'center' }, 
            { label: 'DTQĐ', key: 'doanhThuQD', align: 'center' },
            { label: 'HQQĐ', key: 'hieuQuaValue', align: 'center' }, 
            { label: '%T.Chậm', key: 'dtTraChamPercent_CE_ICT' as SortKey, align: 'center' },
            { label: 'Weak', key: 'weakPointsRevenue' as SortKey, align: 'center', width: 'w-12' }
        ];
    } else if (groupType === 'khaiThac') {
        title = 'Hiệu Quả Khai Thác';
        subTitle = 'Tiếp cận khách hàng & Bán kèm';
        icon = 'layers';
        headers = [
            { label: 'T.Cận', key: 'slTiepCan', align: 'center' }, 
            { label: 'CE/ICT', key: 'slCE_ICT' as SortKey, align: 'center' },
            { label: 'T.Chậm', key: 'slTraCham_CE_ICT' as SortKey, align: 'center' }, 
            { label: '%T.Chậm', key: 'traChamPercent_CE_ICT' as SortKey, align: 'center' },
            { label: 'Weak', key: 'weakPointsExploitation' as SortKey, align: 'center', width: 'w-12' }
        ];
    } else { // vuotTroi
        const todayDate = new Date().toLocaleDateString('vi-VN', {day: '2-digit', month: '2-digit'});
        title = `Mục Tiêu Vượt Trội`;
        subTitle = `Cập nhật ngày ${todayDate}`;
        icon = 'trophy';
        headers = [
            { label: 'Thực', key: 'doanhThuThuc', align: 'center' },
            { label: 'DTQĐ', key: 'doanhThuQD', align: 'center' },
            { label: 'Target', key: 'target' as SortKey, align: 'center' },
            { label: '%HT', key: 'percentHT', align: 'center', width: 'w-24' },
            { label: 'HQQĐ', key: 'hieuQuaValue', align: 'center' },
            { label: 'Vượt', key: 'dtVuot', align: 'center' }
        ];
        dataToRender = outstandingData;
    }

    const handleCopyBottom40 = (e: React.MouseEvent, key: SortKey, label: string) => {
        e.stopPropagation();
        if (!dataToRender) return;
        const allEmployees = Object.values(dataToRender).flat() as any[];
        if (allEmployees.length === 0) return;

        const sorted = [...allEmployees].sort((a, b) => (a[key] ?? 0) - (b[key] ?? 0));
        const initialCutoff = Math.ceil(sorted.length * 0.4);
        const valueAtCutoff = sorted[initialCutoff - 1]?.[key] ?? 0;

        let finalSelection = valueAtCutoff <= 0 ? sorted.filter(emp => (emp[key] ?? 0) <= 0) : sorted.slice(0, initialCutoff);
        const getId = (n: string) => n.split(/[-–]/)[0].trim();

        let content = `⚠️ CẢNH BÁO: DANH SÁCH ${label.toUpperCase()} THẤP (BOTTOM 40%)\nCác bạn sau cần tập trung cải thiện chỉ số này ngay:\n`;
        finalSelection.forEach(e => content += `@${getId(e.name)}\n`);

        navigator.clipboard.writeText(content).then(() => {
            setColumnCopySuccess(String(key));
            setTimeout(() => setColumnCopySuccess(null), 2000);
        });
    };

    const renderHeader = (h: { label: string, key: SortKey, align?: string, width?: string }) => {
        const isTargetHeader = h.label === 'Target' && groupType === 'vuotTroi';
        const canCopy = groupType === 'vuotTroi' && ['doanhThuThuc', 'doanhThuQD', 'percentHT', 'dtVuot', 'hieuQuaValue', 'dtTraChamPercent_CE_ICT'].includes(String(h.key));
        const alignClass = h.align === 'right' ? 'text-right' : h.align === 'center' ? 'text-center' : 'text-left';

        if (isTargetHeader && isEditingTarget) {
            return (
                <th key={String(h.key)} className="px-2 py-3 align-middle">
                    <input 
                        ref={targetInputRef}
                        type="number" 
                        value={tempTarget} 
                        onChange={(e) => setTempTarget(e.target.value)}
                        onBlur={handleSaveTarget}
                        className="w-full px-2 py-1 text-xs text-center border-2 border-indigo-500 rounded-lg bg-white shadow-sm focus:outline-none focus:ring-2 focus:ring-indigo-200"
                        autoFocus
                        onKeyDown={(e) => {
                            if (e.key === 'Enter') handleSaveTarget();
                            if (e.key === 'Escape') setIsEditingTarget(false);
                        }}
                    />
                </th>
            );
        }

        return (
            <th 
                key={String(h.key)}
                onClick={() => isTargetHeader ? (setTempTarget(String(targetPerEmployee)), setIsEditingTarget(true)) : onSort(h.key)}
                className={`px-3 py-3 text-[10px] font-black uppercase tracking-wider text-slate-400 cursor-pointer group/header select-none ${alignClass} ${h.width || ''}`}
            >
                <div className={`flex items-center gap-1 ${h.align === 'right' ? 'justify-end' : h.align === 'center' ? 'justify-center' : 'justify-start'}`}>
                    {h.label}
                    {isTargetHeader && <Icon name="edit-3" size={3} className="opacity-50 group-hover/header:opacity-100" />}
                    {canCopy && (
                        <button onClick={(e) => handleCopyBottom40(e, h.key, h.label)} className="opacity-0 group-hover/header:opacity-100 p-1 hover:text-red-500 transition-opacity">
                            <Icon name="copy" size={3} />
                        </button>
                    )}
                    {sortConfig.key === h.key && (
                        <Icon name={sortConfig.direction === 'asc' ? 'arrow-up' : 'arrow-down'} size={3} className="text-indigo-500" />
                    )}
                </div>
                {columnCopySuccess === String(h.key) && (
                    <div className="absolute inset-0 bg-emerald-500 text-white text-[9px] flex items-center justify-center rounded-lg animate-fade-in">Copied!</div>
                )}
            </th>
        );
    };

    const handleCopyRanking = () => {
        if (groupType !== 'vuotTroi' || !dataToRender) return;
        const allEmployees = Object.values(dataToRender).flat() as any[];
        if (allEmployees.length === 0) return;

        const sorted = [...allEmployees].sort((a, b) => b.percentHT - a.percentHT);
        const top3 = sorted.slice(0, 3);
        const bottom30 = sorted.slice(-Math.ceil(sorted.length * 0.3));
        const getId = (n: string) => n.split(/[-–]/)[0].trim();

        let content = `🌟 VINH DANH TOP 3 CHIẾN BINH XUẤT SẮC 🌟\n`;
        top3.forEach(e => content += `@${getId(e.name)}\n`);
        content += `\n⚠️ CẢNH BÁO ĐỎ: NHÓM CUỐI BẢNG ⚠️\n`;
        bottom30.forEach(e => content += `@${getId(e.name)}\n`);

        navigator.clipboard.writeText(content).then(() => {
            setCopySuccess(true);
            setTimeout(() => setCopySuccess(false), 2000);
        });
    };

    const showDeptHeaders = dataToRender && (Object.keys(dataToRender).length > 1 || (Object.keys(dataToRender).length === 1 && Object.keys(dataToRender)[0] !== 'Không Phân Ca'));
    const medals = ['🥇', '🥈', '🥉'];

    if (!dataToRender || Object.keys(dataToRender).length === 0) {
        return (
            <div ref={tableRef} className="bg-white dark:bg-slate-900 rounded-[1.5rem] shadow-sm border border-slate-100 dark:border-slate-800 p-8 flex flex-col items-center justify-center h-full">
                <Icon name="inbox" size={8} className="text-slate-300 mb-2" />
                <p className="text-slate-500 dark:text-slate-400 font-medium">Không có dữ liệu hiển thị</p>
            </div>
        );
    }

    return (
        <div ref={tableRef} className="bg-white dark:bg-slate-900 rounded-[1.5rem] shadow-sm border border-slate-100 dark:border-slate-800 overflow-hidden flex flex-col h-full">
            {/* Apple-style Card Header */}
            <div 
                className="px-6 py-5 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center bg-white dark:bg-slate-900 sticky top-0 z-20 group/header"
                onClick={handleCopyRanking}
            >
                <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${theme.iconBg} shadow-sm`}>
                        <Icon name={icon} size={6} />
                    </div>
                    <div>
                        <h3 className="text-lg font-black text-slate-800 dark:text-white leading-tight">{title}</h3>
                        <p className="text-xs font-medium text-slate-400">{subTitle}</p>
                    </div>
                </div>

                <div className="flex items-center gap-2 opacity-0 group-hover:header:opacity-100 transition-opacity">
                    {groupType === 'vuotTroi' && (
                        <span className="text-xs font-bold text-slate-400 mr-2 flex items-center gap-1 cursor-pointer">
                            {copySuccess ? <span className="text-emerald-500">Đã chép!</span> : <><Icon name="copy" size={3}/> Copy Top/Bot</>}
                        </span>
                    )}
                    <button 
                        onClick={(e) => { e.stopPropagation(); onSingleExport(); }} 
                        disabled={isExporting} 
                        className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all"
                    >
                        <Icon name="camera" size={5} />
                    </button>
                </div>
            </div>

            <div className="overflow-x-auto custom-scrollbar flex-grow p-2">
                <table className="w-full text-left border-collapse">
                    <thead className="sticky top-0 z-10 bg-white/95 dark:bg-slate-900/95 backdrop-blur-sm">
                        <tr>
                            <th className="px-4 py-3 text-left text-[10px] font-black uppercase tracking-wider text-slate-400 w-12 text-center">#</th>
                            <th onClick={() => onSort('name')} className="px-3 py-3 text-left text-[10px] font-black uppercase tracking-wider text-slate-400 cursor-pointer min-w-[140px]">Nhân Viên</th>
                            {headers.map(h => renderHeader(h))}
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50 dark:divide-slate-800/50">
                        {Object.entries(dataToRender).map(([dept, employees]: [string, any[]]) => {
                            // No re-sorting here; data passed from parent `useMemo` is already sorted.

                            return (
                            <React.Fragment key={dept}>
                                {showDeptHeaders && (
                                    <tr className="bg-slate-50/50 dark:bg-slate-800/20">
                                        <td colSpan={2 + headers.length} className="px-4 py-2 text-xs font-black text-slate-500 uppercase tracking-widest">
                                            <div className="flex items-center gap-2"><Icon name="users" size={3} /> {dept}</div>
                                        </td>
                                    </tr>
                                )}
                                {employees.map((employee: Employee, index: number) => {
                                    const rankIndex = index;
                                    const medal = rankIndex < 3 ? medals[rankIndex] : null;
                                    const rankDisplay = medal ? <span className="text-lg">{medal}</span> : <span className="text-xs font-bold text-slate-400">#{rankIndex + 1}</span>;

                                    return (
                                    <tr key={employee.name} className="group hover:bg-slate-50 dark:hover:bg-slate-800/30 transition-colors">
                                        <td className="px-4 py-3 text-center">{rankDisplay}</td>
                                        <td className="px-3 py-3">
                                            <div onClick={() => onEmployeeClick(employee.name)} className="flex flex-col cursor-pointer">
                                                <span className="text-sm font-bold text-slate-700 dark:text-slate-200 group-hover:text-indigo-600 transition-colors truncate">
                                                    {abbreviateName(employee.name)}
                                                </span>
                                            </div>
                                        </td>
                                        {headers.map(h => (
                                            <td key={h.key} className={`px-3 py-3 text-sm ${h.align === 'right' ? 'text-right' : h.align === 'center' ? 'text-center' : 'text-left'}`}>
                                                <div className="flex flex-col justify-center h-full">
                                                    { h.key === 'doanhThuThuc' && <span className="text-slate-500 font-medium">{formatCurrency(employee.doanhThuThuc)}</span> }
                                                    { h.key === 'doanhThuQD' && <span className="font-bold text-slate-800 dark:text-white">{formatCurrency(employee.doanhThuQD)}</span> }
                                                    { h.key === 'hieuQuaValue' && <span className={`font-bold ${employee.hieuQuaValue < 35 ? 'text-rose-500' : 'text-emerald-600'}`}>{(employee.hieuQuaValue || 0).toFixed(0)}%</span> }

                                                    {/* Custom Metrics with Safe Checks */}
                                                    { h.key === 'dtTraChamPercent_CE_ICT' && <span className={getTraChamPercentClass(employee.dtTraChamPercent_CE_ICT || 0)}>{(employee.dtTraChamPercent_CE_ICT || 0).toFixed(0)}%</span> }
                                                    { h.key === 'weakPointsRevenue' && <span className={`font-black ${employee.weakPointsRevenue > 0 ? 'text-rose-500 bg-rose-50 px-2 rounded' : 'text-slate-300'}`}>{employee.weakPointsRevenue || '-'}</span> }

                                                    { h.key === 'slTiepCan' && <span className="font-bold text-slate-600">{formatQuantity(employee.slTiepCan)}</span> }
                                                    { h.key === 'slCE_ICT' && <span className="text-slate-500">{formatQuantity(employee.slCE_ICT)}</span> }
                                                    { h.key === 'slTraCham_CE_ICT' && <span className="text-slate-500">{formatQuantity(employee.slTraCham_CE_ICT)}</span> }
                                                    { h.key === 'traChamPercent_CE_ICT' && <span className={getTraChamPercentClass(employee.traChamPercent_CE_ICT || 0)}>{(employee.traChamPercent_CE_ICT || 0).toFixed(0)}%</span> }
                                                    { h.key === 'weakPointsExploitation' && <span className={`font-black ${employee.weakPointsExploitation > 0 ? 'text-rose-500 bg-rose-50 px-2 rounded' : 'text-slate-300'}`}>{employee.weakPointsExploitation || '-'}</span> }

                                                    {/* Targets */}
                                                    { h.key === 'target' && <span className="text-slate-400 text-xs">{formatCurrency((employee as any).target, 0).replace('Tr', '')}</span> }
                                                    { h.key === 'percentHT' && (
                                                        <div className="w-full flex flex-col gap-1">
                                                            <div className="flex justify-center">
                                                                <span className={`text-[10px] font-black ${getPercentTextColor((employee as any).percentHT || 0)}`}>{((employee as any).percentHT || 0).toFixed(0)}%</span>
                                                            </div>
                                                            <div className="h-1.5 w-full bg-slate-100 dark:bg-slate-700 rounded-full overflow-hidden">
                                                                <div className={`h-full rounded-full ${getProgressBarColor((employee as any).percentHT || 0)}`} style={{ width: `${Math.min((employee as any).percentHT || 0, 100)}%` }}></div>
                                                            </div>
                                                        </div>
                                                    )}
                                                    { h.key === 'dtVuot' && <span className={`font-bold ${((employee as any).dtVuot || 0) > 0 ? 'text-emerald-600' : 'text-slate-300'}`}>{((employee as any).dtVuot || 0) > 0 ? `+${formatCurrency((employee as any).dtVuot)}` : '-'}</span> }
                                                </div>
                                            </td>
                                        ))}
                                    </tr>
                                )})}
                            </React.Fragment>
                        )})}
                    </tbody>
                    <tfoot className="bg-slate-50 dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800">
                        <tr>
                            <td colSpan={2} className="px-6 py-4 text-xs font-black text-slate-500 uppercase tracking-widest">Tổng cộng</td>
                            {headers.map(h => (
                                <td key={h.key} className={`px-3 py-4 ${h.align === 'right' ? 'text-right' : h.align === 'center' ? 'text-center' : 'text-left'} font-bold text-slate-700 dark:text-slate-200 text-sm`}>
                                    { h.key === 'doanhThuThuc' && formatCurrency(grandTotal?.doanhThuThuc || 0) }
                                    { h.key === 'doanhThuQD' && <span className="text-indigo-600">{formatCurrency(grandTotal?.doanhThuQD || 0)}</span> }
                                    { h.key === 'hieuQuaValue' && <span className={(grandTotal?.hieuQuaValue || 0) < 35 ? 'text-rose-500' : 'text-emerald-600'}>{(grandTotal?.hieuQuaValue || 0).toFixed(0)}%</span> }
                                    { h.key === 'slTiepCan' && formatQuantity(grandTotal?.slTiepCan || 0) }
                                    { h.key === 'dtVuot' && <span className="text-emerald-600">{formatCurrency((grandTotal?.doanhThuQD || 0) - (targetPerEmployee * fullSellerArrayLength))}</span> }
                                    {/* Add other summary fields as needed */}
                                    { !['doanhThuThuc', 'doanhThuQD', 'hieuQuaValue', 'slTiepCan', 'dtVuot'].includes(h.key as string) && '-' }
                                </td>
                            ))}
                        </tr>
                    </tfoot>
                </table>
            </div>
        </div>
    );
});

export default PerformanceTable;

import React, { useMemo, useState, forwardRef, useEffect, useRef } from 'react';
import type { Employee, EmployeeData } from '../../types';
import { abbreviateName, formatCurrency, formatQuantity, formatQuantityWithFraction } from '../../utils/dataUtils';
import { Icon } from '../common/Icon';
import { getPerformanceTableAnalysis } from '../../services/aiService';
import { getThemeMap, saveThemeMap, getDailyTarget, saveDailyTarget } from '../../services/dbService';
import { useDashboardContext } from '../../contexts/DashboardContext';
import { exportElementAsImage } from '../../services/uiService';

declare const lucide: any;

interface PerformanceTableProps {
    employeeData: EmployeeData;
    onEmployeeClick: (employeeName: string) => void;
    onExport?: () => void;
    isExporting?: boolean;
}

type SortKey = keyof Employee | 'name' | 'percentHT' | 'dtVuot' | 'target';
type SortDirection = 'asc' | 'desc';
type GroupType = 'doanhThu' | 'khaiThac' | 'vuotTroi';

const getTraChamPercentClass = (percentage: number) => {
    if (isNaN(percentage)) return 'text-slate-400 font-medium';
    if (percentage >= 45) return 'text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-lg font-bold';
    if (percentage >= 35) return 'text-amber-600 bg-amber-50 px-2 py-0.5 rounded-lg font-bold';
    return 'text-rose-600 bg-rose-50 px-2 py-0.5 rounded-lg font-bold';
};

const getProgressBarColor = (percent: number) => {
    if (percent >= 100) return 'bg-gradient-to-r from-emerald-400 to-teal-500';
    if (percent >= 80) return 'bg-gradient-to-r from-blue-400 to-indigo-500';
    if (percent >= 50) return 'bg-gradient-to-r from-amber-400 to-orange-500';
    return 'bg-gradient-to-r from-red-400 to-rose-500';
};

const getPercentTextColor = (percent: number) => {
    if (percent >= 100) return 'text-emerald-600 dark:text-emerald-400';
    if (percent >= 80) return 'text-blue-600 dark:text-blue-400';
    if (percent >= 50) return 'text-amber-600 dark:text-amber-400';
    return 'text-rose-600 dark:text-rose-400';
};

// Apple-style subtle themes
const themes = {
    vuotTroi: { iconBg: 'bg-indigo-100 text-indigo-600', accent: 'indigo' },
    doanhThu: { iconBg: 'bg-emerald-100 text-emerald-600', accent: 'emerald' },
    khaiThac: { iconBg: 'bg-blue-100 text-blue-600', accent: 'blue' }
};

const RenderSingleTable = ({
    groupType,
    sortConfig,
    onSort,
    tableRef,
    onSingleExport,
    isExporting,
    groupedData,
    outstandingData,
    grandTotal,
    targetPerEmployee,
    fullSellerArrayLength,
    onEmployeeClick,
    isEditingTarget,
    targetInputRef,
    setTargetPerEmployee,
    handleSaveTarget,
    setIsEditingTarget,
    tempTarget,
    setTempTarget,
}: {
    groupType: GroupType;
    sortConfig: { key: SortKey; direction: SortDirection };
    onSort: (key: SortKey) => void;
    tableRef: React.RefObject<HTMLDivElement>;
    onSingleExport: () => void;
    isExporting?: boolean;
    groupedData: { [key: string]: Employee[] };
    outstandingData: { [key: string]: Employee[] };
    grandTotal: any;
    targetPerEmployee: number;
    fullSellerArrayLength: number;
    onEmployeeClick: (name: string) => void;
    isEditingTarget: boolean;
    targetInputRef: React.RefObject<HTMLInputElement>;
    setTargetPerEmployee: (val: number) => void;
    handleSaveTarget: () => void;
    setIsEditingTarget: (val: boolean) => void;
    tempTarget: string;
    setTempTarget: (val: string) => void;
}) => {
    const [copySuccess, setCopySuccess] = useState(false);
    const [columnCopySuccess, setColumnCopySuccess] = useState<string | null>(null);

    let title = "";
    let subTitle = "";
    let icon = "";
    let headers: { label: string, key: SortKey, align?: 'left'|'center'|'right', width?: string }[] = [];
    let dataToRender: any = groupedData;
    const theme = themes[groupType];

    if (groupType === 'doanhThu') {
        title = 'Hiệu Quả Doanh Thu';
        subTitle = 'Phân tích doanh thu & hiệu quả quy đổi';
        icon = 'wallet';
        headers = [
            { label: 'Thực', key: 'doanhThuThuc', align: 'center' }, 
            { label: 'DTQĐ', key: 'doanhThuQD', align: 'center' },
            { label: 'HQQĐ', key: 'hieuQuaValue', align: 'center' }, 
            { label: '%T.Chậm', key: 'dtTraChamPercent_CE_ICT' as SortKey, align: 'center' },
            { label: 'Weak', key: 'weakPointsRevenue' as SortKey, align: 'center', width: 'w-12' }
        ];
    } else if (groupType === 'khaiThac') {
        title = 'Hiệu Quả Khai Thác';
        subTitle = 'Tiếp cận khách hàng & Bán kèm';
        icon = 'layers';
        headers = [
            { label: 'T.Cận', key: 'slTiepCan', align: 'center' }, 
            { label: 'CE/ICT', key: 'slCE_ICT' as SortKey, align: 'center' },
            { label: 'T.Chậm', key: 'slTraCham_CE_ICT' as SortKey, align: 'center' }, 
            { label: '%T.Chậm', key: 'traChamPercent_CE_ICT' as SortKey, align: 'center' },
            { label: 'Weak', key: 'weakPointsExploitation' as SortKey, align: 'center', width: 'w-12' }
        ];
    } else { // vuotTroi
        const todayDate = new Date().toLocaleDateString('vi-VN', {day: '2-digit', month: '2-digit'});
        title = `Mục Tiêu Vượt Trội`;
        subTitle = `Cập nhật ngày ${todayDate}`;
        icon = 'trophy';
        headers = [
            { label: 'Thực', key: 'doanhThuThuc', align: 'center' },
            { label: 'DTQĐ', key: 'doanhThuQD', align: 'center' },
            { label: 'Target', key: 'target' as SortKey, align: 'center' },
            { label: '%HT', key: 'percentHT', align: 'center', width: 'w-24' },
            { label: 'HQQĐ', key: 'hieuQuaValue', align: 'center' },
            { label: 'Vượt', key: 'dtVuot', align: 'center' }
        ];
        dataToRender = outstandingData;
    }

    const handleCopyBottom40 = (e: React.MouseEvent, key: SortKey, label: string) => {
        e.stopPropagation();
        if (!dataToRender) return;
        const allEmployees = Object.values(dataToRender).flat() as any[];
        if (allEmployees.length === 0) return;

        const sorted = [...allEmployees].sort((a, b) => (a[key] ?? 0) - (b[key] ?? 0));
        const initialCutoff = Math.ceil(sorted.length * 0.4);
        const valueAtCutoff = sorted[initialCutoff - 1]?.[key] ?? 0;

        let finalSelection = valueAtCutoff <= 0 ? sorted.filter(emp => (emp[key] ?? 0) <= 0) : sorted.slice(0, initialCutoff);
        const getId = (n: string) => n.split(/[-–]/)[0].trim();

        let content = `⚠️ CẢNH BÁO: DANH SÁCH ${label.toUpperCase()} THẤP (BOTTOM 40%)\nCác bạn sau cần tập trung cải thiện chỉ số này ngay:\n`;
        finalSelection.forEach(e => content += `@${getId(e.name)}\n`);

        navigator.clipboard.writeText(content).then(() => {
            setColumnCopySuccess(String(key));
            setTimeout(() => setColumnCopySuccess(null), 2000);
        });
    };

    const renderHeader = (h: { label: string, key: SortKey, align?: string, width?: string }) => {
        const isTargetHeader = h.label === 'Target' && groupType === 'vuotTroi';
        const canCopy = groupType === 'vuotTroi' && ['doanhThuThuc', 'doanhThuQD', 'percentHT', 'dtVuot', 'hieuQuaValue', 'dtTraChamPercent_CE_ICT'].includes(String(h.key));
        const alignClass = h.align === 'right' ? 'text-right' : h.align === 'center' ? 'text-center' : 'text-left';

        if (isTargetHeader && isEditingTarget) {
            return (
                <th key={String(h.key)} className="px-2 py-3 align-middle">
                    <input 
                        ref={targetInputRef}
                        type="number" 
                        value={tempTarget} 
                        onChange={(e) => setTempTarget(e.target.value)}
                        onBlur={handleSaveTarget}
                        className="w-full px-2 py-1 text-xs text-center border-2 border-indigo-500 rounded-lg bg-white shadow-sm focus:outline-none focus:ring-2 focus:ring-indigo-200"
                        autoFocus
                        onKeyDown={(e) => {
                            if (e.key === 'Enter') handleSaveTarget();
                            if (e.key === 'Escape') setIsEditingTarget(false);
                        }}
                    />
                </th>
            );
        }

        return (
            <th 
                key={String(h.key)}
                onClick={() => isTargetHeader ? (setTempTarget(String(targetPerEmployee)), setIsEditingTarget(true)) : onSort(h.key)}
                className={`px-3 py-3 text-[10px] font-black uppercase tracking-wider text-slate-400 cursor-pointer group/header select-none ${alignClass} ${h.width || ''}`}
            >
                <div className={`flex items-center gap-1 ${h.align === 'right' ? 'justify-end' : h.align === 'center' ? 'justify-center' : 'justify-start'}`}>
                    {h.label}
                    {isTargetHeader && <Icon name="edit-3" size={3} className="opacity-50 group-hover/header:opacity-100" />}
                    {canCopy && (
                        <button onClick={(e) => handleCopyBottom40(e, h.key, h.label)} className="opacity-0 group-hover/header:opacity-100 p-1 hover:text-red-500 transition-opacity">
                            <Icon name="copy" size={3} />
                        </button>
                    )}
                    {sortConfig.key === h.key && (
                        <Icon name={sortConfig.direction === 'asc' ? 'arrow-up' : 'arrow-down'} size={3} className="text-indigo-500" />
                    )}
                </div>
                {columnCopySuccess === String(h.key) && (
                    <div className="absolute inset-0 bg-emerald-500 text-white text-[9px] flex items-center justify-center rounded-lg animate-fade-in">Copied!</div>
                )}
            </th>
        );
    };

    const handleCopyRanking = () => {
        if (groupType !== 'vuotTroi' || !dataToRender) return;
        const allEmployees = Object.values(dataToRender).flat() as any[];
        if (allEmployees.length === 0) return;

        const sorted = [...allEmployees].sort((a, b) => b.percentHT - a.percentHT);
        const top3 = sorted.slice(0, 3);
        const bottom30 = sorted.slice(-Math.ceil(sorted.length * 0.3));
        const getId = (n: string) => n.split(/[-–]/)[0].trim();

        let content = `🌟 VINH DANH TOP 3 CHIẾN BINH XUẤT SẮC 🌟\n`;
        top3.forEach(e => content += `@${getId(e.name)}\n`);
        content += `\n⚠️ CẢNH BÁO ĐỎ: NHÓM CUỐI BẢNG ⚠️\n`;
        bottom30.forEach(e => content += `@${getId(e.name)}\n`);

        navigator.clipboard.writeText(content).then(() => {
            setCopySuccess(true);
            setTimeout(() => setCopySuccess(false), 2000);
        });
    };

    const showDeptHeaders = dataToRender && (Object.keys(dataToRender).length > 1 || (Object.keys(dataToRender).length === 1 && Object.keys(dataToRender)[0] !== 'Không Phân Ca'));
    const medals = ['🥇', '🥈', '🥉'];

    if (!dataToRender || Object.keys(dataToRender).length === 0) {
        return (
            <div ref={tableRef} className="bg-white dark:bg-slate-900 rounded-[1.5rem] shadow-sm border border-slate-100 dark:border-slate-800 p-8 flex flex-col items-center justify-center h-full">
                <Icon name="inbox" size={8} className="text-slate-300 mb-2" />
                <p className="text-slate-500 dark:text-slate-400 font-medium">Không có dữ liệu hiển thị</p>
            </div>
        );
    }

    return (
        <div ref={tableRef} className="bg-white dark:bg-slate-900 rounded-[1.5rem] shadow-sm border border-slate-100 dark:border-slate-800 overflow-hidden flex flex-col h-full">
            {/* Apple-style Card Header */}
            <div 
                className="px-6 py-5 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center bg-white dark:bg-slate-900 sticky top-0 z-20 group/header"
                onClick={handleCopyRanking}
            >
                <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${theme.iconBg} shadow-sm`}>
                        <Icon name={icon} size={6} />
                    </div>
                    <div>
                        <h3 className="text-lg font-black text-slate-800 dark:text-white leading-tight">{title}</h3>
                        <p className="text-xs font-medium text-slate-400">{subTitle}</p>
                    </div>
                </div>

                <div className="flex items-center gap-2 opacity-0 group-hover:header:opacity-100 transition-opacity">
                    {groupType === 'vuotTroi' && (
                        <span className="text-xs font-bold text-slate-400 mr-2 flex items-center gap-1 cursor-pointer">
                            {copySuccess ? <span className="text-emerald-500">Đã chép!</span> : <><Icon name="copy" size={3}/> Copy Top/Bot</>}
                        </span>
                    )}
                    <button 
                        onClick={(e) => { e.stopPropagation(); onSingleExport(); }} 
                        disabled={isExporting} 
                        className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all"
                    >
                        <Icon name="camera" size={5} />
                    </button>
                </div>
            </div>

            <div className="overflow-x-auto custom-scrollbar flex-grow p-2">
                <table className="w-full text-left border-collapse">
                    <thead className="sticky top-0 z-10 bg-white/95 dark:bg-slate-900/95 backdrop-blur-sm">
                        <tr>
                            <th className="px-4 py-3 text-left text-[10px] font-black uppercase tracking-wider text-slate-400 w-12 text-center">#</th>
                            <th onClick={() => onSort('name')} className="px-3 py-3 text-left text-[10px] font-black uppercase tracking-wider text-slate-400 cursor-pointer min-w-[140px]">Nhân Viên</th>
                            {headers.map(h => renderHeader(h))}
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50 dark:divide-slate-800/50">
                        {Object.entries(dataToRender).map(([dept, employees]: [string, any[]]) => {
                            // No re-sorting here; data passed from parent `useMemo` is already sorted.

                            return (
                            <React.Fragment key={dept}>
                                {showDeptHeaders && (
                                    <tr className="bg-slate-50/50 dark:bg-slate-800/20">
                                        <td colSpan={2 + headers.length} className="px-4 py-2 text-xs font-black text-slate-500 uppercase tracking-widest">
                                            <div className="flex items-center gap-2"><Icon name="users" size={3} /> {dept}</div>
                                        </td>
                                    </tr>
                                )}
                                {employees.map((employee: Employee, index: number) => {
                                    const rankIndex = index;
                                    const medal = rankIndex < 3 ? medals[rankIndex] : null;
                                    const rankDisplay = medal ? <span className="text-lg">{medal}</span> : <span className="text-xs font-bold text-slate-400">#{rankIndex + 1}</span>;

                                    return (
                                    <tr key={employee.name} className="group hover:bg-slate-50 dark:hover:bg-slate-800/30 transition-colors">
                                        <td className="px-4 py-3 text-center">{rankDisplay}</td>
                                        <td className="px-3 py-3">
                                            <div onClick={() => onEmployeeClick(employee.name)} className="flex flex-col cursor-pointer">
                                                <span className="text-sm font-bold text-slate-700 dark:text-slate-200 group-hover:text-indigo-600 transition-colors truncate">
                                                    {abbreviateName(employee.name)}
                                                </span>
                                            </div>
                                        </td>
                                        {headers.map(h => (
                                            <td key={h.key} className={`px-3 py-3 text-sm ${h.align === 'right' ? 'text-right' : h.align === 'center' ? 'text-center' : 'text-left'}`}>
                                                <div className="flex flex-col justify-center h-full">
                                                    { h.key === 'doanhThuThuc' && <span className="text-slate-500 font-medium">{formatCurrency(employee.doanhThuThuc)}</span> }
                                                    { h.key === 'doanhThuQD' && <span className="font-bold text-slate-800 dark:text-white">{formatCurrency(employee.doanhThuQD)}</span> }
                                                    { h.key === 'hieuQuaValue' && <span className={`font-bold ${employee.hieuQuaValue < 35 ? 'text-rose-500' : 'text-emerald-600'}`}>{(employee.hieuQuaValue || 0).toFixed(0)}%</span> }

                                                    {/* Custom Metrics with Safe Checks */}
                                                    { h.key === 'dtTraChamPercent_CE_ICT' && <span className={getTraChamPercentClass(employee.dtTraChamPercent_CE_ICT || 0)}>{(employee.dtTraChamPercent_CE_ICT || 0).toFixed(0)}%</span> }
                                                    { h.key === 'weakPointsRevenue' && <span className={`font-black ${employee.weakPointsRevenue > 0 ? 'text-rose-500 bg-rose-50 px-2 rounded' : 'text-slate-300'}`}>{employee.weakPointsRevenue || '-'}</span> }

                                                    { h.key === 'slTiepCan' && <span className="font-bold text-slate-600">{formatQuantity(employee.slTiepCan)}</span> }
                                                    { h.key === 'slCE_ICT' && <span className="text-slate-500">{formatQuantity(employee.slCE_ICT)}</span> }
                                                    { h.key === 'slTraCham_CE_ICT' && <span className="text-slate-500">{formatQuantity(employee.slTraCham_CE_ICT)}</span> }
                                                    { h.key === 'traChamPercent_CE_ICT' && <span className={getTraChamPercentClass(employee.traChamPercent_CE_ICT || 0)}>{(employee.traChamPercent_CE_ICT || 0).toFixed(0)}%</span> }
                                                    { h.key === 'weakPointsExploitation' && <span className={`font-black ${employee.weakPointsExploitation > 0 ? 'text-rose-500 bg-rose-50 px-2 rounded' : 'text-slate-300'}`}>{employee.weakPointsExploitation || '-'}</span> }

                                                    {/* Targets */}
                                                    { h.key === 'target' && <span className="text-slate-400 text-xs">{formatCurrency((employee as any).target, 0).replace('Tr', '')}</span> }
                                                    { h.key === 'percentHT' && (
                                                        <div className="w-full flex flex-col gap-1">
                                                            <div className="flex justify-center">
                                                                <span className={`text-[10px] font-black ${getPercentTextColor((employee as any).percentHT || 0)}`}>{((employee as any).percentHT || 0).toFixed(0)}%</span>
                                                            </div>
                                                            <div className="h-1.5 w-full bg-slate-100 dark:bg-slate-700 rounded-full overflow-hidden">
                                                                <div className={`h-full rounded-full ${getProgressBarColor((employee as any).percentHT || 0)}`} style={{ width: `${Math.min((employee as any).percentHT || 0, 100)}%` }}></div>
                                                            </div>
                                                        </div>
                                                    )}
                                                    { h.key === 'dtVuot' && <span className={`font-bold ${((employee as any).dtVuot || 0) > 0 ? 'text-emerald-600' : 'text-slate-300'}`}>{((employee as any).dtVuot || 0) > 0 ? `+${formatCurrency((employee as any).dtVuot)}` : '-'}</span> }
                                                </div>
                                            </td>
                                        ))}
                                    </tr>
                                )})}
                            </React.Fragment>
                        )})}
                    </tbody>
                    <tfoot className="bg-slate-50 dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800">
                        <tr>
                            <td colSpan={2} className="px-6 py-4 text-xs font-black text-slate-500 uppercase tracking-widest">Tổng cộng</td>
                            {headers.map(h => (
                                <td key={h.key} className={`px-3 py-4 ${h.align === 'right' ? 'text-right' : h.align === 'center' ? 'text-center' : 'text-left'} font-bold text-slate-700 dark:text-slate-200 text-sm`}>
                                    { h.key === 'doanhThuThuc' && formatCurrency(grandTotal?.doanhThuThuc || 0) }
                                    { h.key === 'doanhThuQD' && <span className="text-indigo-600">{formatCurrency(grandTotal?.doanhThuQD || 0)}</span> }
                                    { h.key === 'hieuQuaValue' && <span className={(grandTotal?.hieuQuaValue || 0) < 35 ? 'text-rose-500' : 'text-emerald-600'}>{(grandTotal?.hieuQuaValue || 0).toFixed(0)}%</span> }
                                    { h.key === 'slTiepCan' && formatQuantity(grandTotal?.slTiepCan || 0) }
                                    { h.key === 'dtVuot' && <span className="text-emerald-600">{formatCurrency((grandTotal?.doanhThuQD || 0) - (targetPerEmployee * fullSellerArrayLength))}</span> }
                                    {/* Add other summary fields as needed */}
                                    { !['doanhThuThuc', 'doanhThuQD', 'hieuQuaValue', 'slTiepCan', 'dtVuot'].includes(h.key as string) && '-' }
                                </td>
                            ))}
                        </tr>
                    </tfoot>
                </table>
            </div>
        </div>
    );
};

const PerformanceTable = forwardRef<HTMLDivElement, PerformanceTableProps>(({ employeeData, onEmployeeClick, onExport, isExporting }, ref) => {
    const { processedData, warehouseTargets } = useDashboardContext();
    const [targetPerEmployee, setTargetPerEmployee] = useState(0); 
    const [isEditingTarget, setIsEditingTarget] = useState(false);
    const [tempTarget, setTempTarget] = useState('');
    const targetInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        getDailyTarget().then(t => setTargetPerEmployee(t || 15000000));
    }, []);

    const handleSaveTarget = () => {
        const val = parseInt(tempTarget.replace(/\D/g, ''), 10);
        if (!isNaN(val)) {
            setTargetPerEmployee(val);
            saveDailyTarget(val);
        }
        setIsEditingTarget(false);
    };

    const [sortDoanhThu, setSortDoanhThu] = useState<{key: SortKey, direction: SortDirection}>({ key: 'doanhThuQD', direction: 'desc' });
    const [sortKhaiThac, setSortKhaiThac] = useState<{key: SortKey, direction: SortDirection}>({ key: 'slTiepCan', direction: 'desc' });
    const [sortVuotTroi, setSortVuotTroi] = useState<{key: SortKey, direction: SortDirection}>({ key: 'percentHT', direction: 'desc' });

    const dtRef = useRef<HTMLDivElement>(null);
    const ktRef = useRef<HTMLDivElement>(null);
    const vtRef = useRef<HTMLDivElement>(null);

    const groupedData = useMemo(() => {
        const groups: { [key: string]: Employee[] } = {};
        employeeData.fullSellerArray.forEach(emp => {
            if (!groups[emp.department]) groups[emp.department] = [];
            groups[emp.department].push(emp);
        });
        return groups;
    }, [employeeData]);

    const getSortedGroupedData = (sortConfig: {key: SortKey, direction: SortDirection}) => {
        const sortedGroups: { [key: string]: Employee[] } = {};
        Object.keys(groupedData).sort().forEach(dept => {
            sortedGroups[dept] = [...groupedData[dept]].sort((a, b) => {
                const valA = (a as any)[sortConfig.key] || 0;
                const valB = (b as any)[sortConfig.key] || 0;
                return sortConfig.direction === 'asc' ? valA - valB : valB - valA;
            });
        });
        return sortedGroups;
    };

    const outstandingData = useMemo(() => {
        const dataWithTarget = employeeData.fullSellerArray.map(emp => {
            const empTarget = targetPerEmployee; 
            const percentHT = empTarget > 0 ? (emp.doanhThuQD / empTarget) * 100 : 0;
            const dtVuot = Math.max(0, emp.doanhThuQD - empTarget);
            return { ...emp, target: empTarget, percentHT, dtVuot };
        });

        const groups: { [key: string]: Employee[] } = {};
        dataWithTarget.forEach(emp => {
            if (!groups[emp.department]) groups[emp.department] = [];
            groups[emp.department].push(emp);
        });

        const sortedGroups: { [key: string]: Employee[] } = {};
        Object.keys(groups).sort().forEach(dept => {
            sortedGroups[dept] = groups[dept].sort((a: any, b: any) => {
                const valA = a[sortVuotTroi.key] || 0;
                const valB = b[sortVuotTroi.key] || 0;
                return sortVuotTroi.direction === 'asc' ? valA - valB : valB - valA;
            });
        });

        return sortedGroups;
    }, [employeeData, targetPerEmployee, sortVuotTroi]);

    const [analysis, setAnalysis] = useState<string | null>(null);
    const [isAnalysisLoading, setIsAnalysisLoading] = useState(false);

    const handleAiAnalysis = async () => {
        setIsAnalysisLoading(true);
        setAnalysis(null);
        try {
            const result = await getPerformanceTableAnalysis(employeeData);
            setAnalysis(result);
        } catch (e) {
            setAnalysis("Lỗi phân tích.");
        } finally {
            setIsAnalysisLoading(false);
        }
    };

    const handleSingleExport = async (elementRef: React.RefObject<HTMLDivElement>, filename: string) => {
        if (elementRef.current && onExport) {
            await exportElementAsImage(elementRef.current, filename, { isCompactTable: true });
        }
    };

    // Calculate totals for tables (using averages for now as per design pattern or sums if preferred)
    // Here we use employeeData.averages for simplicity as it contains keys like doanhThuThuc, etc.
    // But for counts like slTiepCan we might want sums. 
    // Let's create a combined totals object.
    const totals = useMemo(() => {
        return employeeData.fullSellerArray.reduce((acc, emp) => {
            acc.doanhThuThuc += emp.doanhThuThuc;
            acc.doanhThuQD += emp.doanhThuQD;
            acc.slTiepCan += emp.slTiepCan;
            return acc;
        }, { doanhThuThuc: 0, doanhThuQD: 0, slTiepCan: 0, hieuQuaValue: 0 });
    }, [employeeData]);

    // Add calculated fields to totals
    (totals as any).hieuQuaValue = totals.doanhThuThuc > 0 ? ((totals.doanhThuQD - totals.doanhThuThuc) / totals.doanhThuThuc) * 100 : 0;

    return (
        <div ref={ref} className="space-y-8">
            <div className="flex justify-between items-center hide-on-export">
                 <button 
                    onClick={handleAiAnalysis} 
                    disabled={isAnalysisLoading} 
                    className="flex items-center gap-2 px-4 py-2 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 rounded-lg hover:bg-indigo-100 dark:hover:bg-indigo-900/50 transition-colors"
                >
                    {isAnalysisLoading ? <Icon name="loader-2" className="animate-spin" /> : <Icon name="sparkles" />}
                    <span>AI Phân Tích Hiệu Suất</span>
                </button>
            </div>

            {analysis && (
                <div className="p-4 bg-indigo-50 dark:bg-indigo-900/20 border border-indigo-100 dark:border-indigo-800 rounded-xl text-sm text-slate-700 dark:text-slate-300 whitespace-pre-wrap">
                    <div className="flex items-center gap-2 font-bold text-indigo-700 dark:text-indigo-400 mb-2">
                        <Icon name="sparkles" size={4} /> Nhận xét từ AI
                    </div>
                    {analysis}
                </div>
            )}

            <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
                <RenderSingleTable
                    groupType="doanhThu"
                    sortConfig={sortDoanhThu}
                    onSort={(key) => setSortDoanhThu(prev => ({ key, direction: prev.key === key && prev.direction === 'desc' ? 'asc' : 'desc' }))}
                    tableRef={dtRef}
                    onSingleExport={() => handleSingleExport(dtRef, 'hieu-qua-doanh-thu.png')}
                    isExporting={isExporting}
                    groupedData={getSortedGroupedData(sortDoanhThu)}
                    outstandingData={{}} 
                    grandTotal={totals} 
                    targetPerEmployee={0} fullSellerArrayLength={0} onEmployeeClick={onEmployeeClick}
                    isEditingTarget={false} targetInputRef={targetInputRef} setTargetPerEmployee={() => {}} handleSaveTarget={() => {}} setIsEditingTarget={() => {}} tempTarget="" setTempTarget={() => {}}
                />

                <RenderSingleTable
                    groupType="khaiThac"
                    sortConfig={sortKhaiThac}
                    onSort={(key) => setSortKhaiThac(prev => ({ key, direction: prev.key === key && prev.direction === 'desc' ? 'asc' : 'desc' }))}
                    tableRef={ktRef}
                    onSingleExport={() => handleSingleExport(ktRef, 'hieu-qua-khai-thac.png')}
                    isExporting={isExporting}
                    groupedData={getSortedGroupedData(sortKhaiThac)}
                    outstandingData={{}} 
                    grandTotal={totals}
                    targetPerEmployee={0} fullSellerArrayLength={0} onEmployeeClick={onEmployeeClick}
                    isEditingTarget={false} targetInputRef={targetInputRef} setTargetPerEmployee={() => {}} handleSaveTarget={() => {}} setIsEditingTarget={() => {}} tempTarget="" setTempTarget={() => {}}
                />
            </div>

            <div className="mt-8">
                <RenderSingleTable
                    groupType="vuotTroi"
                    sortConfig={sortVuotTroi}
                    onSort={(key) => setSortVuotTroi(prev => ({ key, direction: prev.key === key && prev.direction === 'desc' ? 'asc' : 'desc' }))}
                    tableRef={vtRef}
                    onSingleExport={() => handleSingleExport(vtRef, 'muc-tieu-vuot-troi.png')}
                    isExporting={isExporting}
                    groupedData={{}} 
                    outstandingData={outstandingData}
                    grandTotal={totals}
                    targetPerEmployee={targetPerEmployee}
                    fullSellerArrayLength={employeeData.fullSellerArray.length}
                    onEmployeeClick={onEmployeeClick}
                    isEditingTarget={isEditingTarget}
                    targetInputRef={targetInputRef}
                    setTargetPerEmployee={setTargetPerEmployee}
                    handleSaveTarget={handleSaveTarget}
                    setIsEditingTarget={setIsEditingTarget}
                    tempTarget={tempTarget}
                    setTempTarget={setTempTarget}
                />
            </div>
        </div>
    );
});

export default PerformanceTable;

import React, { useMemo, useState, forwardRef, useEffect, useRef } from 'react';
import type { Employee, EmployeeData } from '../../types';
import { abbreviateName, formatCurrency, formatQuantity } from '../../utils/dataUtils';
import { Icon } from '../common/Icon';
import { getDailyTarget, saveDailyTarget } from '../../services/dbService';

declare const lucide: any;

interface PerformanceTableProps {
    employeeData: EmployeeData;
    onEmployeeClick: (employeeName: string) => void;
    onExport?: () => void;
    isExporting?: boolean;
}

type SortKey = keyof Employee | 'name' | 'percentHT' | 'dtVuot' | 'target';
type SortDirection = 'asc' | 'desc';
type GroupType = 'doanhThu' | 'khaiThac' | 'vuotTroi';

const getTraChamPercentClass = (percentage: number) => {
    if (isNaN(percentage)) return 'text-slate-400 font-medium';
    if (percentage >= 45) return 'text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-lg font-bold';
    if (percentage >= 35) return 'text-amber-600 bg-amber-50 px-2 py-0.5 rounded-lg font-bold';
    return 'text-rose-600 bg-rose-50 px-2 py-0.5 rounded-lg font-bold';
};

const getProgressBarColor = (percent: number) => {
    if (percent >= 100) return 'bg-gradient-to-r from-emerald-400 to-teal-500';
    if (percent >= 80) return 'bg-gradient-to-r from-blue-400 to-indigo-500';
    if (percent >= 50) return 'bg-gradient-to-r from-amber-400 to-orange-500';
    return 'bg-gradient-to-r from-red-400 to-rose-500';
};

const getPercentTextColor = (percent: number) => {
    if (percent >= 100) return 'text-emerald-600 dark:text-emerald-400';
    if (percent >= 80) return 'text-blue-600 dark:text-blue-400';
    if (percent >= 50) return 'text-amber-600 dark:text-amber-400';
    return 'text-rose-600 dark:text-rose-400';
};

// Safe sort function to prevent crashes
const safeSort = (a: any, b: any, key: string, direction: SortDirection) => {
    const valA = a[key];
    const valB = b[key];

    // Handle null/undefined values safely
    if (valA === valB) return 0;
    if (valA === undefined || valA === null) return 1; // Push undefined to bottom
    if (valB === undefined || valB === null) return -1;

    if (typeof valA === 'number' && typeof valB === 'number') {
        return direction === 'asc' ? valA - valB : valB - valA;
    }

    // String comparison
    const strA = String(valA).toLowerCase();
    const strB = String(valB).toLowerCase();
    if (strA < strB) return direction === 'asc' ? -1 : 1;
    if (strA > strB) return direction === 'asc' ? 1 : -1;

    return 0;
};

const themes = {
    vuotTroi: { iconBg: 'bg-indigo-100 text-indigo-600', accent: 'indigo' },
    doanhThu: { iconBg: 'bg-emerald-100 text-emerald-600', accent: 'emerald' },
    khaiThac: { iconBg: 'bg-blue-100 text-blue-600', accent: 'blue' }
};

const RenderSingleTable = ({
    groupType,
    sortConfig,
    onSort,
    tableRef,
    onSingleExport,
    isExporting,
    groupedData,
    outstandingData,
    grandTotal,
    targetPerEmployee,
    onEmployeeClick,
    isEditingTarget,
    targetInputRef,
    setTargetPerEmployee,
    handleSaveTarget,
    setIsEditingTarget,
    tempTarget,
    setTempTarget,
}: {
    groupType: GroupType;
    sortConfig: { key: string; direction: SortDirection };
    onSort: (key: SortKey) => void;
    tableRef: React.RefObject<HTMLDivElement>;
    onSingleExport: () => void;
    isExporting?: boolean;
    groupedData: { [key: string]: Employee[] };
    outstandingData: { [key: string]: Employee[] };
    grandTotal: any;
    targetPerEmployee: number;
    onEmployeeClick: (name: string) => void;
