}) => {
    const [columnCopySuccess, setColumnCopySuccess] = useState<string | null>(null);

    let title = "";
    let subTitle = "";
    let icon = "";
    let headers: { label: string, key: string, align?: 'left'|'center'|'right', width?: string }[] = [];
