                                                    { h.key === 'slCE_ICT' && <span className="text-slate-500">{formatQuantity(employee.slCE_ICT)}</span> }
                                                    { h.key === 'slTraCham_CE_ICT' && <span className="text-slate-500">{formatQuantity(employee.slTraCham_CE_ICT)}</span> }
